--
-- Name: get_nearby_apartments(uuid, double precision, integer, integer, double precision, double precision); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_nearby_apartments(uid uuid, range_km double precision DEFAULT 100, offset_value integer DEFAULT 0, page_limit integer DEFAULT 10, source_latitude double precision DEFAULT 100, source_longitude double precision DEFAULT 100) RETURNS TABLE(id bigint, apartment_description text, rent real, photos json, amenities_available json, is_available boolean, user_id uuid, start_date bigint, end_date bigint, beds smallint, baths smallint, created_at timestamp with time zone, address text, distance_m double precision, latitude double precision, longitude double precision, location gis.geometry, apartment_likes json)
    LANGUAGE plpgsql
    AS $$
DECLARE
    search_location gis.geography;
BEGIN
    -- If source_latitude and source_longitude are provided, convert them to gis.geography
    IF source_latitude IS NOT NULL AND source_longitude IS NOT NULL THEN
        search_location := gis.ST_SetSRID(gis.ST_MakePoint(source_longitude, source_latitude), 4326);
    ELSE
        -- Otherwise, get the university location for the given user_id
        SELECT u.location INTO search_location
        FROM public.user_details AS ud
        INNER JOIN const.universities AS u ON ud.college = u.title
        WHERE ud.id = uid;
    END IF;

    -- Return nearby apartments with like information
    RETURN QUERY
    SELECT
        a.id AS id,
        a.apartment_description,
        a.rent,
        a.photos,
        a.amenities_available,
        a.is_available,
        a.user_id,
        a.start_date,
        a.end_date,
        a.beds,
        a.baths,
        a.created_at,
        a.address,
        gis.ST_Distance(a.location::gis.geography, search_location) AS distance_m,
        gis.ST_Y(a.location::gis.geometry) AS latitude,
        gis.ST_X(a.location::gis.geometry) AS longitude,
        a.location::gis.geometry,
        -- Include like information as JSON
        json_build_object(
            'is_liked', COALESCE(al.is_liked, false)
        ) AS apartment_likes
    FROM public.apartments AS a
    -- Left join with apartment_likes to get like status for this user
    LEFT JOIN public.apartment_likes AS al 
        ON a.id = al.apartment_id 
        AND al.user_id = uid
    WHERE 
        -- Filter by distance
        gis.ST_DWithin(a.location::gis.geography, search_location, range_km * 1000)
        -- Exclude apartments created by the calling user
        AND a.user_id != uid
    ORDER BY distance_m
    OFFSET offset_value LIMIT page_limit;
END;
$$;


ALTER FUNCTION public.get_nearby_apartments(uid uuid, range_km double precision, offset_value integer, page_limit integer, source_latitude double precision, source_longitude double precision) OWNER TO postgres;

--
-- Name: get_nearby_marketplaces(uuid, double precision, integer, integer, double precision, double precision); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_nearby_marketplaces(uid uuid, range_km double precision DEFAULT 100, offset_value integer DEFAULT 0, page_limit integer DEFAULT 10, source_latitude double precision DEFAULT 100, source_longitude double precision DEFAULT 100) RETURNS TABLE(id bigint, name text, category json, description text, price integer, photos json, link json, period json, is_available boolean, user_id uuid, created_at bigint, address text, distance_m double precision, latitude double precision, longitude double precision, marketplaces_likes json)
    LANGUAGE plpgsql
    AS $$
DECLARE
    search_location gis.geography;
BEGIN
    -- Convert source coordinates to geography if provided
    IF source_latitude IS NOT NULL AND source_longitude IS NOT NULL THEN
        search_location := gis.ST_SetSRID(
            gis.ST_MakePoint(source_longitude, source_latitude), 4326
        );
    ELSE
        -- Get university location for the given user_id if no source coordinates provided
        SELECT u.location INTO search_location
        FROM public.user_details AS ud
        INNER JOIN const.universities AS u ON ud.college = u.title
        WHERE ud.id = uid;
    END IF;

    -- Return nearby marketplaces with like information
    RETURN QUERY
    SELECT
        m.id AS id,
        m.name,
        m.category,
        m.description,
        m.price,
        m.photos,
        m.link,
        m.period,
        m.is_available,
        m.user_id,
        m.created_at,
        m.address,
        gis.ST_Distance(m.location::gis.geography, search_location) AS distance_m,
        gis.ST_Y(m.location::gis.geometry) AS latitude,
        gis.ST_X(m.location::gis.geometry) AS longitude,
        json_build_object(
            'is_liked', COALESCE(ml.is_liked, false)
        ) AS marketplaces_likes
    FROM public.marketplaces AS m
    LEFT JOIN public.marketplaces_likes AS ml ON 
        m.id = ml.marketplace_id AND 
        ml.user_id = uid
    WHERE 
        gis.ST_DWithin(m.location::gis.geography, search_location, range_km * 1000) AND
        m.user_id != uid  -- Exclude marketplaces created by the calling user
    ORDER BY distance_m
    OFFSET offset_value LIMIT page_limit;
END;
$$;


