--
-- Name: get_nearby_sublets(uuid, double precision, integer, integer, double precision, double precision); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_nearby_sublets(uid uuid, range_km double precision DEFAULT 100, offset_value integer DEFAULT 0, page_limit integer DEFAULT 10, source_latitude double precision DEFAULT 100, source_longitude double precision DEFAULT 100) RETURNS TABLE(sublet_id bigint, room_description text, roommate_description text, roommate_gender_pref text, rent real, photos json, amenities_available json, room_type text, is_available boolean, user_id uuid, start_date bigint, end_date bigint, beds smallint, baths smallint, created_at timestamp with time zone, address text, distance_m double precision, latitude double precision, longitude double precision, location gis.geography, sublet_likes json)
    LANGUAGE plpgsql
    AS $$
DECLARE
    university_location gis.geography;
    search_location gis.geography;
BEGIN
    -- If source_latitude and source_longitude are provided, convert them to gis.geography
    IF source_latitude IS NOT NULL AND source_longitude IS NOT NULL THEN
        search_location := gis.ST_SetSRID(gis.ST_MakePoint(source_longitude, source_latitude), 4326);
    ELSE
        -- Otherwise, get the university location for the given user_id
        SELECT u.location INTO university_location
        FROM public.user_details AS ud
        INNER JOIN const.universities AS u ON ud.college = u.title
        WHERE ud.id = uid;
        search_location := university_location;
    END IF;

    -- Return nearby sublets based on the search location with pagination and distance
    RETURN QUERY
    SELECT
        s.id AS sublet_id,
        s.room_description,
        s.roommate_description,
        s.roommate_gender_pref,
        s.rent,
        s.photos,
        s.amenities_available,
        s.room_type,
        s.is_available,
        s.user_id,
        s.start_date,
        s.end_date,
        s.beds,
        s.baths,
        s.created_at,
        s.address,
        gis.ST_Distance(s.location::gis.geography, search_location) AS distance_m,
        gis.ST_Y(s.location::gis.geometry) AS latitude,
        gis.ST_X(s.location::gis.geometry) AS longitude,
        s.location::gis.geography,
        -- Add sublet_likes JSON with is_liked status
        json_build_object(
            'is_liked', COALESCE(sl.is_liked, false)
        ) AS sublet_likes
    FROM public.sublets AS s
    -- Left join with sublet_likes to check if current user has liked the sublet
    LEFT JOIN public.sublet_likes AS sl ON s.id = sl.sublet_id AND sl.user_id = uid
    WHERE gis.ST_DWithin(s.location::gis.geography, search_location, range_km * 1000)
    -- Exclude sublets created by the calling user
    AND s.user_id != uid
    ORDER BY distance_m
    OFFSET offset_value LIMIT page_limit;
END;
$$;


ALTER FUNCTION public.get_nearby_sublets(uid uuid, range_km double precision, offset_value integer, page_limit integer, source_latitude double precision, source_longitude double precision) OWNER TO postgres;

--
-- Name: get_users(uuid, text, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_users(exclude_user uuid, target_college text, offset_value integer DEFAULT 0, page_limit integer DEFAULT 10) RETURNS TABLE(id uuid, full_name text, profile_image text, selected_course_name text, college text, city text, state text, country text, work_experience smallint, intake_period text, intake_year smallint, has_roommate_found boolean)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    (
        -- Get users from the same college first, excluding the specified user
        SELECT
            u.id,
            u.full_name,
            u.profile_image,
            u.selected_course_name,
            u.college,
            u.city,
            u.state,
            u.country,
            u.work_experience,
            u.intake_period,
            u.intake_year,
            u.has_roommate_found
        FROM public.user_details u
        WHERE 
            u.college = target_college AND
            u.id != exclude_user
        ORDER BY 
            u.intake_year DESC, 
            u.intake_period DESC
        LIMIT page_limit 
        OFFSET offset_value * page_limit
    )
    UNION ALL
    (
        -- Get users from other colleges after the same college users are exhausted
        SELECT
            u.id,
            u.full_name,
            u.profile_image,
            u.selected_course_name,
            u.college,
            u.city,
            u.state,
            u.country,
            u.work_experience,
            u.intake_period,
            u.intake_year,
            u.has_roommate_found
        FROM public.user_details u
        WHERE 
            u.college != target_college AND
            u.id != exclude_user
        ORDER BY 
            u.intake_year DESC, 
            u.intake_period DESC
        LIMIT page_limit 
        OFFSET offset_value * page_limit
    );
END;
$$;


ALTER FUNCTION public.get_users(exclude_user uuid, target_college text, offset_value integer, page_limit integer) OWNER TO postgres;

--
-- Name: search_marketplace_items(text, uuid, double precision, double precision, double precision); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.search_marketplace_items(search_query text, uid uuid, source_latitude double precision DEFAULT 100, source_longitude double precision DEFAULT 100, range_km double precision DEFAULT 100) RETURNS TABLE(id bigint, name text, category json, description text, price integer, photos json, link json, period json, is_available boolean, user_id uuid, created_at bigint, address text, distance_m double precision, latitude double precision, longitude double precision, match_by text)
    LANGUAGE plpgsql
    AS $$
DECLARE
    search_location gis.geography;
BEGIN
    -- Convert source coordinates to geography if provided
    IF source_latitude IS NOT NULL AND source_longitude IS NOT NULL THEN
        search_location := gis.ST_SetSRID(
            gis.ST_MakePoint(source_longitude, source_latitude), 4326
        );
    ELSE
        -- Get university location for the given user_id if no source coordinates provided
        SELECT u.location INTO search_location
        FROM public.user_details AS ud
        INNER JOIN const.universities AS u ON ud.college = u.title
        WHERE ud.id = uid;
    END IF;

    RETURN QUERY
    SELECT
        m.id AS id,
        m.name,
        m.category,
        m.description,
        m.price,
        m.photos,
        m.link,
        m.period,
        m.is_available,
        m.user_id,
        m.created_at,
        m.address,
        gis.ST_Distance(m.location::gis.geography, search_location) AS distance_m,
        gis.ST_Y(m.location::gis.geometry) AS latitude,
        gis.ST_X(m.location::gis.geometry) AS longitude,
        CASE
            WHEN m.name ILIKE '%' || search_query || '%' THEN 'name'
            WHEN m.description ILIKE '%' || search_query || '%' THEN 'description'
            WHEN m.category->>'name' ILIKE '%' || search_query || '%' THEN 'category'
            WHEN m.address ILIKE '%' || search_query || '%' THEN 'address'
            ELSE 'unknown'
        END AS match_by
    FROM public.marketplaces AS m
    WHERE 
        gis.ST_DWithin(m.location::gis.geography, search_location, range_km * 1000) AND
        (m.name ILIKE '%' || search_query || '%' OR
         m.description ILIKE '%' || search_query || '%' OR
         m.category->>'name' ILIKE '%' || search_query || '%' OR
         m.address ILIKE '%' || search_query || '%') AND
        m.user_id != uid  -- Exclude items posted by the current user
    ORDER BY distance_m;
END;
$$;


ALTER FUNCTION public.search_marketplace_items(search_query text, uid uuid, source_latitude double precision, source_longitude double precision, range_km double precision) OWNER TO postgres;

